using System.Collections.Generic;
using UnityEngine;

/// <summary>Política de respawn de um inimigo (Etapa 7.3).</summary>
public enum EnemyRespawnMode
{
    /// <summary>Inimigo comum: volta quando o player sai e reentra na área (EnemyRespawnZone). Não volta enquanto o player permanecer na área.</summary>
    Comum,

    /// <summary>Inimigo especial: NUNCA volta depois de derrotado (registado permanentemente em PlayerProgress.defeatedEnemyIds).</summary>
    Especial,

    /// <summary>Mini-boss: não respawna após derrotado, salvo "miniBossCanRespawn".</summary>
    MiniBoss
}

/// <summary>
/// Respawn e persistência de um inimigo (Enemy Creator — Etapa 7.3):
///
/// - Comum: <see cref="TryRespawn"/> (chamado por EnemyRespawnZone quando o
///   player reentra na área) faz reset completo — vida, drops comuns, posição,
///   estado. Enquanto o player está na mesma área, mortos não voltam.
/// - Especial / MiniBoss (sem "miniBossCanRespawn"): ao morrer/desactivar por
///   dano, é registado permanentemente em PlayerProgress.defeatedEnemyIds e
///   nunca volta (desactiva o GameObject em Start nas próximas visitas).
/// - Desactivado por variável global (Etapa 5.4): mesmo após reset, a condição
///   continua verdadeira e volta a desactivá-lo — permanece desactivado.
/// - Drops únicos: bloqueados pelo registo em PlayerProgress (Etapa 4.3),
///   mesmo que o inimigo respawne.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
public class EnemyRespawn : MonoBehaviour
{
    /// <summary>Todas as instâncias activas (usado por EnemyRespawnZone para encontrar inimigos da sua área).</summary>
    public static readonly List<EnemyRespawn> All = new List<EnemyRespawn>();

    [Header("Política de Respawn (Etapa 7.3)")]
    public EnemyRespawnMode mode = EnemyRespawnMode.Comum;

    [Tooltip("Só para MiniBoss: permite respawnar mesmo depois de derrotado (configuração contrária ao padrão).")]
    public bool miniBossCanRespawn = false;

    [Tooltip("ID usado no registo permanente de derrotados (Especial/MiniBoss). Vazio = usa o Enemy Instance Id do EnemyController.")]
    public string persistenceId = "";

    private EnemyController _controller;
    private EnemyHealth _health;
    private EnemyDropTable _dropTable;

    /// <summary>ID efectivo de persistência (persistenceId, ou o Enemy Instance Id).</summary>
    public string PersistenceId => !string.IsNullOrEmpty(persistenceId) ? persistenceId : _controller.EnemyInstanceId;

    /// <summary>True se este inimigo nunca deve voltar depois de derrotado.</summary>
    public bool IsPermanent => mode == EnemyRespawnMode.Especial ||
                               (mode == EnemyRespawnMode.MiniBoss && !miniBossCanRespawn);

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _health = GetComponent<EnemyHealth>();
        _dropTable = GetComponent<EnemyDropTable>();
    }

    private void OnEnable()
    {
        All.Add(this);
        _controller.OnStateChanged += HandleStateChanged;
    }

    private void OnDisable()
    {
        All.Remove(this);
        _controller.OnStateChanged -= HandleStateChanged;
    }

    private void Start()
    {
        // Derrotado permanentemente numa visita anterior: não volta a aparecer.
        if (IsPermanent && PlayerProgress.Instance != null && PlayerProgress.Instance.HasDefeatedEnemy(PersistenceId))
            gameObject.SetActive(false);
    }

    private void HandleStateChanged(EnemyState oldState, EnemyState newState)
    {
        if (newState != EnemyState.Morto && newState != EnemyState.Desactivado) return;
        if (!IsPermanent) return;

        // Só conta como "derrotado para sempre" se tiver ID de persistência.
        string id = PersistenceId;
        if (string.IsNullOrEmpty(id))
        {
            Debug.LogWarning($"[{name}] EnemyRespawn (modo {mode}) sem 'persistenceId' nem 'Enemy Instance Id' — a derrota não fica registada permanentemente.", this);
            return;
        }

        PlayerProgress.Instance?.MarkEnemyDefeated(id);
    }

    /// <summary>
    /// Tenta respawnar este inimigo (chamado por EnemyRespawnZone quando o
    /// player reentra na área). Derrotados permanentes não voltam; os restantes
    /// fazem reset completo (posição/vida/drops comuns/estado).
    /// </summary>
    public void TryRespawn()
    {
        if (IsPermanent && PlayerProgress.Instance != null && PlayerProgress.Instance.HasDefeatedEnemy(PersistenceId))
        {
            gameObject.SetActive(false);
            return;
        }

        ResetEnemy();
    }

    /// <summary>Reset completo: HomePosition, vida, drops comuns (únicos continuam bloqueados pelo registo no PlayerProgress) e estado (ResetState → Idle).</summary>
    public void ResetEnemy()
    {
        if (!gameObject.activeSelf) gameObject.SetActive(true);

        transform.position = _controller.HomePosition;

        if (_controller.Rb != null)
            _controller.Rb.linearVelocity = Vector2.zero;

        if (_health != null) _health.ResetHealth();
        if (_dropTable != null) _dropTable.ResetDrops();

        _controller.Target = null;
        _controller.ResetState(EnemyState.Idle);
    }
}
